import{_ as a,H as t,f as e,i}from"./chunks/framework.BHvCMIhP.js";const c=JSON.parse('{"title":"merge 合并与冲突","description":"","frontmatter":{},"headers":[],"relativePath":"gitLearning/07-merge合并与冲突.md","filePath":"gitLearning/07-merge合并与冲突.md","lastUpdated":1778496697000}'),n={name:"gitLearning/07-merge合并与冲突.md"};function p(l,s,r,h,o,d){return t(),e("div",null,[...s[0]||(s[0]=[i(`<h1 id="merge-合并与冲突" tabindex="-1">merge 合并与冲突 <a class="header-anchor" href="#merge-合并与冲突" aria-label="Permalink to &quot;merge 合并与冲突&quot;">​</a></h1><p>merge 是 git 协作的核心动作,也是新人<strong>最怕的那个动作</strong>。怕的本质不是 merge 难,是<strong>冲突 marker 看不懂、不知道怎么解、不知道解完接着干什么</strong>。这一篇彻底打掉这个恐惧——merge 就是把两个 commit 的 diff 叠一起放进新 commit;冲突就是&quot;叠一起的两段在同一行&quot;——看 diff、留对的、删 marker、commit,完事。</p><blockquote><p>一句话先记住:<strong>merge 永远不会偷偷改你东西</strong>——产生冲突时它把决定权留给你。冲突 marker <code>&lt;&lt;&lt;&lt;&lt;&lt;&lt; ======= &gt;&gt;&gt;&gt;&gt;&gt;&gt;</code> 把两边内容并排摆给你看,你选哪边或写新的,然后 commit——这就是全部。<strong>git 冲突解决从来不需要&quot;高级技巧&quot;,只需要清楚的头脑</strong>。</p></blockquote><hr><h2 id="一、merge-的三种情形" tabindex="-1">一、merge 的三种情形 <a class="header-anchor" href="#一、merge-的三种情形" aria-label="Permalink to &quot;一、merge 的三种情形&quot;">​</a></h2><h3 id="_1-1-fast-forward-可快进" tabindex="-1">1.1 Fast-forward(可快进) <a class="header-anchor" href="#_1-1-fast-forward-可快进" aria-label="Permalink to &quot;1.1 Fast-forward(可快进)&quot;">​</a></h3><p>main 没动,feature 比 main 多几个 commit:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A → B → C       ← main</span></span>
<span class="line"><span>        ↘</span></span>
<span class="line"><span>         D → E  ← feature</span></span></code></pre></div><p><code>git merge feature</code> 直接把 main 指针移到 E,<strong>不新建 merge commit</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A → B → C → D → E      ← main, feature</span></span></code></pre></div><p>历史<strong>完全线性</strong>——这是最干净的合并结果。</p><h3 id="_1-2-three-way-merge-三方合并" tabindex="-1">1.2 Three-way merge(三方合并) <a class="header-anchor" href="#_1-2-three-way-merge-三方合并" aria-label="Permalink to &quot;1.2 Three-way merge(三方合并)&quot;">​</a></h3><p>main 和 feature 都各自动了:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A → B → C → F          ← main</span></span>
<span class="line"><span>        ↘</span></span>
<span class="line"><span>         D → E         ← feature</span></span></code></pre></div><p><code>git merge feature</code> 必须新建 merge commit M(两个 parent):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A → B → C → F ─→ M     ← main</span></span>
<span class="line"><span>        ↘       ↗</span></span>
<span class="line"><span>         D → E ┘       ← feature</span></span></code></pre></div><p>历史<strong>保留分叉</strong>——能看出&quot;feature 是独立做的&quot;。</p><h3 id="_1-3-冲突合并-conflicting-merge" tabindex="-1">1.3 冲突合并(conflicting merge) <a class="header-anchor" href="#_1-3-冲突合并-conflicting-merge" aria-label="Permalink to &quot;1.3 冲突合并(conflicting merge)&quot;">​</a></h3><p>两边都改了<strong>同一文件的同一行</strong>(或一边删了另一边改了):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>main:    foo = 1</span></span>
<span class="line"><span>feature: foo = 2</span></span></code></pre></div><p>git 不知道你想要哪个,<strong>停下来问你</strong>。这就是&quot;冲突&quot;。</p><blockquote><p>merge 三种情形发生的概率大致是 4 : 4 : 2——大部分 PR 不会有冲突;有了也通常 1-2 处。<strong>&quot;冲突很难解&quot;是被传谣的</strong>。</p></blockquote><hr><h2 id="二、最简-merge-流程" tabindex="-1">二、最简 merge 流程 <a class="header-anchor" href="#二、最简-merge-流程" aria-label="Permalink to &quot;二、最简 merge 流程&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 切到要&quot;接收改动&quot;的分支</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> switch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 拉一下,确保 main 是最新</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 合并 feature 进来</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> merge</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature</span></span></code></pre></div><p>可能的结果:</p><table tabindex="0"><thead><tr><th>结果</th><th>你做什么</th></tr></thead><tbody><tr><td><code>Already up to date.</code></td><td>feature 没新东西</td></tr><tr><td><code>Fast-forward</code></td><td>已合,无新 commit</td></tr><tr><td><code>Merge made by the &#39;ort&#39; strategy.</code></td><td>新建了 merge commit,合好了</td></tr><tr><td><code>CONFLICT (...)</code></td><td>出冲突,见下面第三节</td></tr></tbody></table><p>合完看一眼:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> log</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --oneline</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --graph</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -10</span></span></code></pre></div><hr><h2 id="三、冲突-marker-怎么读" tabindex="-1">三、冲突 marker 怎么读 <a class="header-anchor" href="#三、冲突-marker-怎么读" aria-label="Permalink to &quot;三、冲突 marker 怎么读&quot;">​</a></h2><p>冲突文件里 git 会插入一段标记:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;&lt;&lt;&lt;&lt;&lt;&lt; HEAD</span></span>
<span class="line"><span>const TIMEOUT = 1000;</span></span>
<span class="line"><span>=======</span></span>
<span class="line"><span>const TIMEOUT = 5000;</span></span>
<span class="line"><span>&gt;&gt;&gt;&gt;&gt;&gt;&gt; feature</span></span></code></pre></div><p>逐行解读:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;&lt;&lt;&lt;&lt;&lt;&lt; HEAD              ← 我&quot;当前所在那边&quot;的开始</span></span>
<span class="line"><span>const TIMEOUT = 1000;     ← 当前分支(main)的内容</span></span>
<span class="line"><span>=======                   ← 分隔线</span></span>
<span class="line"><span>const TIMEOUT = 5000;     ← 要合进来那边(feature)的内容</span></span>
<span class="line"><span>&gt;&gt;&gt;&gt;&gt;&gt;&gt; feature           ← 结束</span></span></code></pre></div><p>你的任务:<strong>手工编辑这段,留下你想要的最终代码,把 marker 全删掉</strong>。比如选 5000:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>const TIMEOUT = 5000;</span></span></code></pre></div><p>或者选两边都不要,写个新的:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>const TIMEOUT = parseInt(process.env.TIMEOUT) || 3000;</span></span></code></pre></div><p><strong>完事四步</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. 编辑冲突文件,留对的、删 marker</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. 标记已解决(实际是 add 进 staging)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/config.ts</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. 检查所有冲突都解了</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 不应该再有 &quot;Unmerged paths&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 4. 完成合并</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 默认会带一段 &quot;Merge branch &#39;feature&#39; ...&quot; 的 message</span></span></code></pre></div><blockquote><p><strong>解冲突不是猜——是想清楚&quot;两边分别想表达什么&quot;</strong>。如果 main 的 1000 是为了快速失败、feature 的 5000 是为了适配慢网络——那合理结果可能是 5000(因为最新需求);也可能是按环境分开。<strong>搞不清楚就问那个加 5000 的人</strong>。</p></blockquote><hr><h2 id="四、merge-中途想撤销" tabindex="-1">四、merge 中途想撤销 <a class="header-anchor" href="#四、merge-中途想撤销" aria-label="Permalink to &quot;四、merge 中途想撤销&quot;">​</a></h2><p>冲突解到一半发现&quot;算了不合了&quot;?</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> merge</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --abort</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 完全撤销 merge,回到 merge 前状态</span></span></code></pre></div><p><strong>这是安全网</strong>——任何时候都能放弃 merge 重来。<strong><code>--abort</code> 是 merge 操作的&quot;反悔键&quot;</strong>,记住这一条就敢动 merge。</p><hr><h2 id="五、merge-的几种策略-s" tabindex="-1">五、merge 的几种策略(<code>-s</code>) <a class="header-anchor" href="#五、merge-的几种策略-s" aria-label="Permalink to &quot;五、merge 的几种策略(\`-s\`)&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> merge</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> recursive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 默认,2.30 之前</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> merge</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ort</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # 默认,2.34+(更快)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> merge</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ours</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # 强制保留我这边,完全忽略 feature 的内容</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> merge</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> theirs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # ❌ 不存在,见下</span></span></code></pre></div><p>注意:<code>-s ours</code> 是&quot;保留我这边的所有内容,但记下&#39;已合并 feature&#39;这个事实&quot;。<strong>不是常用操作</strong>——典型场景是&quot;丢弃一条侧支但记下它合过&quot;。</p><p>想&quot;对方优先&quot;,用:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> merge</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> theirs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 注意是大写 X,且 X 是策略选项,不是 strategy</span></span></code></pre></div><p><code>-X ours</code> / <code>-X theirs</code> 在<strong>有冲突时偏向哪边</strong>——没冲突的部分两边都要。</p><table tabindex="0"><thead><tr><th>选项</th><th>行为</th></tr></thead><tbody><tr><td><code>-s ours</code></td><td>完全丢弃 feature,只记一笔 merge</td></tr><tr><td><code>-X ours</code></td><td>有冲突时选 main 那边,无冲突的还是合</td></tr><tr><td><code>-X theirs</code></td><td>有冲突时选 feature 那边</td></tr></tbody></table><blockquote><p><code>-X theirs</code> 是<strong>自动化批量合 dependabot PR</strong> 的常见招——明知&quot;对方都是版本号 bump,冲突时一律选新的&quot;。</p></blockquote><hr><h2 id="六、-no-ff、-ff、-ff-only" tabindex="-1">六、<code>--no-ff</code>、<code>--ff</code>、<code>--ff-only</code> <a class="header-anchor" href="#六、-no-ff、-ff、-ff-only" aria-label="Permalink to &quot;六、\`--no-ff\`、\`--ff\`、\`--ff-only\`&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>行为</th></tr></thead><tbody><tr><td><code>--ff</code>(默认)</td><td>能 fast-forward 就 fast-forward,否则三方合并</td></tr><tr><td><code>--no-ff</code></td><td><strong>永远新建 merge commit</strong>,即使能 fast-forward</td></tr><tr><td><code>--ff-only</code></td><td><strong>只允许 fast-forward</strong>,不行就报错</td></tr></tbody></table><p>什么时候用哪个:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 个人开发,不想要 merge commit 噪声</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> merge</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 团队规范要求每个 PR 都留一个 merge commit(为了清晰拓扑)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> merge</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-ff</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 严格 trunk-based,要求&quot;feature 必须 rebase 到最新 main 才能合&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> merge</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ff-only</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 不行就报错,提示 rebase</span></span></code></pre></div><blockquote><p>团队大了之后<code>--no-ff</code> 是常见选择——每个 PR 都有自己的 merge commit,<strong>revert 整个 PR 一行 <code>git revert -m 1 &lt;merge-commit&gt;</code> 就行</strong>。fast-forward 会&quot;摊平&quot;这个边界,要 revert 整 PR 反而麻烦。</p></blockquote><hr><h2 id="七、squash-merge" tabindex="-1">七、Squash merge <a class="header-anchor" href="#七、squash-merge" aria-label="Permalink to &quot;七、Squash merge&quot;">​</a></h2><p><strong>把 feature 的 N 个 commit 压成一个 commit 进 main</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> switch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> merge</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --squash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 把 feature 的 diff 合进 staging,但不 commit 也不更新分支指针</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;feat: ...&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 自己写一个汇总 commit</span></span></code></pre></div><p><strong>结果</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A → B → C → F → S          ← main</span></span>
<span class="line"><span>        ↘</span></span>
<span class="line"><span>         D → E              ← feature(没动)</span></span></code></pre></div><p>S 是一个<strong>普通 commit</strong>(只有一个 parent),包含 feature 全部改动,<strong>但 D / E 不在 main 的祖先链里</strong>。</p><table tabindex="0"><thead><tr><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td>main 历史超干净:每个 PR 一个 commit</td><td>feature 上的精细历史丢了(D / E 找不到)</td></tr><tr><td>适合&quot;feature 内部 commit 都是 wip&quot;</td><td>revert 时只能整体 revert</td></tr><tr><td>易 cherry-pick(就一个 commit)</td><td>协作时 feature 分支别人也在用会很乱</td></tr></tbody></table><blockquote><p>GitHub 的 &quot;Squash and merge&quot; 按钮就是这个。<strong>99% 个人 / 小团队 PR 都用 squash 就行</strong>——main 历史等于&quot;一个 PR 一个 commit&quot;,日后看清爽极了。</p></blockquote><hr><h2 id="八、octopus-merge-多分支同时合" tabindex="-1">八、Octopus merge(多分支同时合) <a class="header-anchor" href="#八、octopus-merge-多分支同时合" aria-label="Permalink to &quot;八、Octopus merge(多分支同时合)&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> merge</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature3</span></span></code></pre></div><p>一次合多个分支。<strong>仅用于大批&quot;非冲突的小改动&quot;</strong>,有冲突就报错,不能交互式解决。</p><p><strong>几乎没人用</strong>——典型场景只有 Linux 内核这种<strong>子树合并</strong>特别多的项目。日常工作可以忘掉。</p><hr><h2 id="九、几个解冲突的工具" tabindex="-1">九、几个解冲突的工具 <a class="header-anchor" href="#九、几个解冲突的工具" aria-label="Permalink to &quot;九、几个解冲突的工具&quot;">​</a></h2><h3 id="_9-1-git-mergetool" tabindex="-1">9.1 <code>git mergetool</code> <a class="header-anchor" href="#_9-1-git-mergetool" aria-label="Permalink to &quot;9.1 \`git mergetool\`&quot;">​</a></h3><p>调用图形化合并工具(vimdiff / meld / kdiff3 / VS Code):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> merge.tool</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vscode</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mergetool.vscode.cmd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;code --wait $MERGED&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mergetool</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                  # 出冲突后跑这条</span></span></code></pre></div><p><strong>比手工编辑 marker 快</strong>——左中右三栏看 base / mine / theirs,点选合成。</p><h3 id="_9-2-ide-集成" tabindex="-1">9.2 IDE 集成 <a class="header-anchor" href="#_9-2-ide-集成" aria-label="Permalink to &quot;9.2 IDE 集成&quot;">​</a></h3><p>VS Code 装&quot;GitLens&quot;或者直接用内建 merge editor:每个 conflict block 上方有 &quot;Accept Current / Incoming / Both&quot; 按钮——一键解。</p><h3 id="_9-3-rerere-重用已解的冲突" tabindex="-1">9.3 <code>rerere</code>(重用已解的冲突) <a class="header-anchor" href="#_9-3-rerere-重用已解的冲突" aria-label="Permalink to &quot;9.3 \`rerere\`(重用已解的冲突)&quot;">​</a></h3><p>设过 <code>git config --global rerere.enabled true</code> 之后:</p><ul><li>第一次解某个冲突,git 记下来</li><li>下次同样冲突再出现(rebase 一长串 commit 时常发生),git 自动应用之前的解法</li></ul><p><strong>节省 80% 的&quot;重复解同一个冲突&quot;的痛苦</strong>。</p><hr><h2 id="十、merge-commit-的-message-怎么写" tabindex="-1">十、merge commit 的 message 怎么写 <a class="header-anchor" href="#十、merge-commit-的-message-怎么写" aria-label="Permalink to &quot;十、merge commit 的 message 怎么写&quot;">​</a></h2><p>默认 merge commit message:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Merge branch &#39;feature&#39; into main</span></span></code></pre></div><p>如果你用 <code>--no-ff</code> 或者远端的 PR merge,<strong>最好带上</strong>:</p><ul><li>这个 PR 解决什么问题</li><li>PR 编号</li><li>跟谁有关</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Merge branch &#39;feature/auth-okta&#39; into main</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Implement Okta SSO. Fall back to password login if </span></span>
<span class="line"><span>OKTA_CLIENT_ID is unset. Closes #1234.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Reviewed-by: Wang</span></span></code></pre></div><blockquote><p>GitHub 的 &quot;Create a merge commit&quot; 选项默认会带上 PR 标题和 commits 列表——直接用就行。</p></blockquote><hr><h2 id="十一、踩坑提醒" tabindex="-1">十一、踩坑提醒 <a class="header-anchor" href="#十一、踩坑提醒" aria-label="Permalink to &quot;十一、踩坑提醒&quot;">​</a></h2><ol><li><strong>冲突时不看 marker 就 <code>git add</code> 提交</strong>——marker 字符进了代码,编译报错,丢人</li><li><strong>不知道 <code>--abort</code></strong>——卡在冲突里不敢动,删仓库重来</li><li><strong>merge 完不看 log</strong>——以为合了,实际上漏 commit / 没 commit</li><li><strong>拿到冲突就慌</strong>——冲突 marker 是&quot;git 把决定权留给你&quot;,不是 git 在抽风</li><li><strong>squash merge 之后还以为 feature 分支可以继续用</strong>——squash 没把 feature 标记为 merged,后续 <code>merge --no-ff</code> 会重复合一遍</li><li><strong>强行 <code>-X theirs</code> 解决一切冲突</strong>——有时候 ours 是对的,无脑选 theirs 会把自己的 fix 弄丢</li><li><strong>大量冲突一边解一边 <code>git add</code></strong>——半天不 commit,中途网断 / 关机 / 切分支可能丢解的进度;<strong>解一个 add 一个,但 commit 等全部解完</strong></li></ol><hr><p>下一篇:<code>08-rebase深入.md</code>,讲 rebase 的&quot;重写历史&quot;本质、interactive rebase 改老 commit、<code>onto</code> 三角参数、rebase 和 merge 的取舍、为什么 &quot;golden rule of rebase&quot; 那么严格。</p>`,101)])])}const k=a(n,[["render",p]]);export{c as __pageData,k as default};
